var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"咳……！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아아, 가여워라.","JPN":"ああ、かわいそう。","ENG":"Oh, how pitiful.","TWN":"哀哀，好慘。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"기껏 전력으로 싸워주게 됐는데, 벌써 지친 거야?","JPN":"せっかく全力で戦ってあげようと思ったのに、もう疲れちゃったの？","ENG":"I gave you the honor of fighting me at full power, but you're exhausted already?","TWN":"難得我打得這麼認真，你這麼快就不行啦？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"사나에, 상처가……!","JPN":"早苗、傷が……！","ENG":"Sanae, your wound...!","TWN":"早苗，你的傷口……！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님! 이쪽으로 오시면…… 안 됩니다.","JPN":"ご当主様！　こちらに来ては……なりません。","ENG":"Lady Nanahara! You must... stay back.","TWN":"堂主！不可以……過來。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_NPC_UNION_NULL","text":{"KOREA":"유다님, 결계옥의 방출파장에 변화가 생겼습니다. 말씀하신 안정화단계에 다다른 듯합니다.","JPN":"ユダ様、結界玉の放出波長に変化が見られます。おっしゃっていた安定化段階に至ったようです。","ENG":"The barrier's wave frequency has changed, sir. I believe we are reaching the stabilization phase, just as you said.","TWN":"報告，結界玉石的釋放波長發生變化，似乎已經到達您說的穩定化階段。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"음, 이제 영혼과 그릇을 융합하는 과정만 남았군.","JPN":"うむ、あとは魂と器を融合するだけか。","ENG":"Hmm, now all that is left is for the soul and vessel to fuse into one.","TWN":"嗯，接下來只剩下融合靈魂和器皿的過程。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"레노어, 실험체를 데려와라. 방해되는 것들은 이제 처분해도 상관없다.","JPN":"レノア、実験体を連れてこい。邪魔者はもう処分して構わない。","ENG":"Lenore, bring me my test subject. You can do as you please with the others.","TWN":"蕾諾雅，把實驗體帶過來，閒雜人等一律處理掉。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"네, 아버지.","JPN":"はい、お父様。","ENG":"Yes, father.","TWN":"是，父親。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"들었지? 이제 너희는 쓸모가 없어졌어.","JPN":"聞いた？　もうお前たちは用済みになったの。","ENG":"Hear that? You're useless now.","TWN":"聽到沒？現在你們已經無用武之處。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"살고 싶으면 옆으로 빌빌 기어서 꺼져버리지 그래?","JPN":"生きたけりゃ脇にでも這っていってそのまま逃げれば？","ENG":"How about you crawl aside if you want to live, hmm?","TWN":"想活命就乖乖滾到一邊去！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"넘어가고 싶다면……","JPN":"通りたくば……","ENG":"You can only take her...","TWN":"想越過我的話……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"덤벼라.","JPN":"かかってこい。","ENG":"over my dead body.","TWN":"就儘管試試看！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아, 그래.","JPN":"あ、そう。","ENG":"Sure.","TWN":"喔，好吧。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그럼 소원대로 죽여 줄게!","JPN":"じゃあ、お望みどおり殺してあげる！","ENG":"Then I'll give you what you wish.","TWN":"那我就如你所願殺光你們！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"하압!","JPN":"はあっ！","ENG":"Haargh!","TWN":"呼呼！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"벌써 사앵지섬을 완벽하게 숙달하셨군요. 역시 훌륭하십니다, 치후유님.","JPN":"もう糸桜之閃を完全に習得しましたね。さすがです、千冬様。","ENG":"Amazing, Miss Chifuyu. You have already mastered the Cherry Blossom Slash.","TWN":"您已經可以完美掌握聖安吉島的精髓，果然很優秀呢，千冬。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"이걸로 저도 당주님을 지킬 수 있는 겁니까?","JPN":"これで私も当主を守れるでしょうか？","ENG":"Will I be able to protect Lady Nanahara with this?","TWN":"那我也可以保護堂主了嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"물론입니다. 뿐만 아니라, 치후유님이라면 나나하라류의 경지를 넘어서실 수도 있을 겁니다.","JPN":"もちろんです。それどころか、千冬様なら七原流の高みを超えることもできるでしょう。","ENG":"Of course. Not just that, you might even be able to transcend to a new level of the Nanahara Style.","TWN":"那當然，而且您一定能夠超越七原流的極限。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"죄송합니다, 스승님.","JPN":"申し訳ありません、師匠。","ENG":"My apologies, master.","TWN":"對不起，師父。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……갑자기 왜 그러시는지요?","JPN":"……急にどうなさいましたか？","ENG":"...Why do you say that?","TWN":"……為什麼突然道歉？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"실은 사요 장로님께서…… 제가 검술을 연습하는 걸 보셨습니다.","JPN":"実は小夜長老に……私が剣術の稽古をするところを見られてしまいました。","ENG":"Elder Sayo... She saw me practicing the swordsmanship.","TWN":"其實……小夜長老有看到我在練習劍法。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"꾸짖으셨습니까?","JPN":"叱られましたか?","ENG":"Did she scold you?","TWN":"她有責怪您嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"아닙니다. 칭찬하셨습니다.","JPN":"いいえ。褒められました。","ENG":"Not at all. She praised me.","TWN":"沒有，她是稱讚我。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그렇다면 다행이고 잘된 일입니다. 앞으로는 어디서든 떳떳하게 수련하실 수 있겠군요.","JPN":"それなら幸いでござました。これからはどこででも堂々と修練できますね。","ENG":"Then everything is all good. Now, you will be able to practice anywhere without feeling guilty.","TWN":"那不是很好嗎？以後您就可以公開大方地練劍囉。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"그런데…… 사요님께서는……","JPN":"しかし……小夜様は……","ENG":"But... Elder Sayo said...","TWN":"可是……小夜長老……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"하야미 가문이 없어도 이렇게 훌륭한 무사가 태어난다…… 라고 말씀하셨습니다.","JPN":"速水家がなくてもこのように立派な武士が生まれる……とおっしゃいました。","ENG":"That even without the Hayami family... a great warrior is born...","TWN":"她說……即使沒有速水家族，也會有如此優秀的武士誕生。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"몰랐습니다. 이 검술이 하야미 가문에게 그토록 중요하다는 것을.","JPN":"知りませんでした。この剣術が速水家にとってそれほど大事なものだということを。","ENG":"I didn't know that this swordsmanship was important to the Hayami family.","TWN":"我不知道這個劍法對速水家族那麼重要。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"……죄송합니다. 저는 아무래도, 이 검술을 배울 자격이 없는 것 같습니다.","JPN":"……すみません。どうやら私は、この剣術を教わる資格がないようです。","ENG":"...I'm sorry. Maybe, I don't deserve to learn this.","TWN":"……對不起，我好像沒資格學習這個劍法。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"어째서 치후유님에게 자격이 없다고 생각하십니까?","JPN":"どうして千冬様に資格がないと思われるのですか？","ENG":"Why do you think so, Chifuyu?","TWN":"為什麼您會覺得自己沒資格呢？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"다른 가문 분들이 힘들게 쌓아온 업적을…… 이런 식으로 빼앗고 싶지 않았습니다.","JPN":"他の家の方々が苦労して積んできた業績を……このように奪いたくはありません。","ENG":"I don't want to steal something... that the other families worked hard to achieve.","TWN":"我不想用這種方式……搶走其他家族好不容易累積起來的成就。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"그런데 스승님께선 제가 배우겠다고 고집을 부려 억지로……!","JPN":"師匠は私が教わりたいと意地を張ったので仕方なく……！","ENG":"But you took me in just because I kept pushing you to–!","TWN":"是因為我堅持要學，師父才會……！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"틀렸습니다.","JPN":"違います。","ENG":"You are wrong.","TWN":"不對。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"……예?","JPN":"……はい？","ENG":"...Come again?","TWN":"……什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"제가 치후유님을 가르치는 것은 온전한 제 의지입니다.","JPN":"私が千冬様をお教えするのはすべて私の意志です。","ENG":"I am teaching you on my own will, Miss Chifuyu.","TWN":"我會教您劍法完全是我自己的意思。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"하지만…… 제가 사흘 밤낮을 매달리지 않았더라면…… 스승님께선……","JPN":"しかし……私が三日間お願いしなければ……師匠は……","ENG":"But... If I didn't beg for three days straight, then...","TWN":"但是……要不是我沒有哀求師父三天三夜……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그날 저에게 하셨던 말씀을 기억하시는지요?","JPN":"あの日私におっしゃった言葉を覚えていますか？","ENG":"Do you remember what you said to me that day?","TWN":"您還記得您那天對我說過的話嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님을 지키고 싶다…… 라고.","JPN":"当主を守りたい……と。","ENG":"You said, \\"I want to protect Lady Nanahara\\".","TWN":"您說……想保護堂主。"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그때 저의 눈에 비친 것은 가문의 검술을 빼앗으려는 고집쟁이가 아니라……","JPN":"あの時私の目に映ったのは家門の剣術を奪おうとする意地っ張りではなく……","ENG":"What I saw in you was not some stubborn child who wanted to steal my family's swordsmanship...","TWN":"那時候，我眼裡看到的不是一個想要搶走家族劍法的死腦筋……"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……가장 사랑하는 사람을 곁에서 지키고 싶어하는 한 소녀였습니다.","JPN":"……大好きな人をそばで守りたいと願う一人の少女でした。","ENG":"...But a girl who wanted to protect her beloved.","TWN":"……而是一個想在最愛的人身邊保護她的少女。"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"넌……?","JPN":"お前は……？","ENG":"You're...?","TWN":"你……？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유……?","JPN":"千冬……？","ENG":"Chifuyu...?","TWN":"千冬……？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……치후유님? 어째서 여기에……?","JPN":"……千冬様？　どうしてこちらに……？","ENG":"...Miss Chifuyu? Why are you here...?","TWN":"……千冬？您為什麼會在這裡……？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나나하라류 제1사범, 나나하라 치후유.","JPN":"七原流第一師範、七原千冬。","ENG":"First Instructor of the Nanahara Style, Nanahara Chifuyu.","TWN":"七原流第一師範，七原千冬，"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님을 지키기 위해, 가세하겠습니다.","JPN":"当主を守るため、加勢します。","ENG":"I will join the fight to protect Lady Nanahara.","TWN":"宣布加入戰局，堂主由我來保護。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};